rule.example:
// Runs in build-tools (default) — no wrapping needed
sh "git diff origin/main...HEAD > git-diff.txt"
sh "mvn test"

rule.incorrect:
// Wrong — bob isn't in build-tools
sh "bob -p 'review this'"

// Redundant — askBob already does this
container('bob') {
    askBob(prompt, 'mode-slug')
}

rule.example:
container('oc-tools') {
    sh "oc whoami"
    sh "oc get pods"
}

rule.good:
container('oc-tools') {
    sh "oc rollout status deployment/myapp"
    sh "oc get pods -l app=myapp"
}

def analysis1 = askBob(prompt1, 'mode-1')
def analysis2 = askBob(prompt2, 'mode-2')

rule.bad:
container('oc-tools') { sh "oc rollout status deployment/myapp" }
askBob(prompt1, 'mode-1')
container('oc-tools') { sh "oc get pods -l app=myapp" }
askBob(prompt2, 'mode-2')

pattern.example:
stage('PR Review') {
    steps {
        script {
            // Default container (build-tools) — git is here
            sh '''
                git config --global --add safe.directory "$WORKSPACE"
                git diff origin/main...HEAD > git-diff.txt
            '''

            // askBob switches to bob container internally
            def analysis = askBob(
                "Read git-diff.txt and tell me what changed in this PR.",
                'pipeline-git-diff-overview'
            )

            echo analysis
            writeFile file: 'bob-pr-review.md', text: analysis
            archiveArtifacts artifacts: 'bob-pr-review.md', allowEmptyArchive: true
        }
    }
}

stage('Unit Tests') {
    steps {
        script {
            // build-tools is default; mvn runs here
            sh "mvn -f order-service/pom.xml test || true"

            def reports = sh(
                script: "find order-service/target/surefire-reports -name '*.txt' -exec cat {} +",
                returnStdout: true
            ).trim()

            def analysis = askBob(
                "Analyze these test failures and suggest fixes:\n${reports}",
                'pipeline-test-failure-analyzer'
            )

            echo analysis
        }
    }
}
